// client/src/pages/admin/AdminDashboard.js
import React, { useState, useEffect } from "react";
import api from "../../services/api";
import useAuth from "../../hooks/useAuth";
import io from "socket.io-client";

const AdminDashboard = () => {
  const [metrics, setMetrics] = useState({});
  const [parcels, setParcels] = useState([]);
  const [agents, setAgents] = useState([]);
  const { logout } = useAuth();

  useEffect(() => {
    fetchMetrics();
    fetchParcels();
    fetchAgents();

    const socket = io("http://localhost:5001");
    socket.on("new_booking", (newParcel) => {
      setParcels((prev) => [newParcel, ...prev]);
      fetchMetrics(); // Refresh metrics
    });

    return () => socket.disconnect();
  }, []);

  const fetchMetrics = async () =>
    api.get("/admin/dashboard").then((res) => setMetrics(res.data));
  const fetchParcels = async () =>
    api.get("/admin/parcels").then((res) => setParcels(res.data));
  const fetchAgents = async () =>
    api
      .get("/admin/users")
      .then((res) =>
        setAgents(res.data.filter((u) => u.role === "Delivery Agent"))
      );

  const handleAssignAgent = async (parcelId, agentId) => {
    if (!agentId) return;
    try {
      await api.put(`/admin/parcels/${parcelId}/assign`, { agentId });
      fetchParcels(); // Refresh parcel list
    } catch (error) {
      console.error("Failed to assign agent", error);
    }
  };

  const handleExport = async () => {
    try {
      const response = await api.get("/admin/reports/csv", {
        responseType: "blob",
      });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download", "parcels-report.csv");
      document.body.appendChild(link);
      link.click();
    } catch (error) {
      console.error("Failed to export report", error);
    }
  };

  return (
    <div>
      <h1>Admin Dashboard</h1>
      <button onClick={logout}>Logout</button>
      <hr />
      <h2>Metrics</h2>
      <p>Daily Bookings: {metrics.dailyBookings}</p>
      <p>Failed Deliveries: {metrics.failedDeliveries}</p>
      <p>Total COD Received: ${metrics.totalCodAmount}</p>
      <button onClick={handleExport}>Export All Parcels (CSV)</button>
      <hr />
      <h2>All Parcels</h2>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Customer</th>
            <th>Status</th>
            <th>Agent</th>
            <th>Assign Agent</th>
          </tr>
        </thead>
        <tbody>
          {parcels.map((p) => (
            <tr key={p._id}>
              <td>{p._id}</td>
              <td>{p.customer?.name}</td>
              <td>{p.status}</td>
              <td>{p.deliveryAgent?.name || "Unassigned"}</td>
              <td>
                <select
                  onChange={(e) => handleAssignAgent(p._id, e.target.value)}
                  disabled={p.deliveryAgent}
                >
                  <option value="">Select Agent</option>
                  {agents.map((a) => (
                    <option key={a._id} value={a._id}>
                      {a.name}
                    </option>
                  ))}
                </select>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AdminDashboard;
